# Reinstantiate PatientMemory
import chromadb
from chromadb.utils.embedding_functions import OllamaEmbeddingFunction
from uuid import uuid4

_embed_fn = OllamaEmbeddingFunction(
    url="http://localhost:11434/api/embeddings",
    model_name="nomic-embed-text",
)

class PatientMemory:
    def __init__(self, patient_id: str):
        self.client = chromadb.PersistentClient(path=f"./memory_{patient_id}")
        self.store  = self.client.get_or_create_collection(
            name="memory",
            embedding_function=_embed_fn,
        )

    def remember(self, text: str) -> None:
        clean = redact_pii(text)
        self.store.add(documents=[clean], ids=[str(uuid4())])

    def recall(self, query: str, k: int = 3) -> str:
        if self.store.count() == 0:
            return ""
        results = self.store.query(query_texts=[query], n_results=min(k, self.store.count()))
        return "\n".join(results["documents"][0])

