# [1. BUFFER + SUMMARY MEMORY]

# 1a. BUFFER MEMORY
BUFFER_WINDOW = 5
buffer_memory = []

def buffer_chat(user_input: str) -> str:
    context = rag_retrieve(user_input)
    buffer_memory.append({"role": "user", "content": user_input})
    response = complete([
        {"role": "system", "content": (
            "You are a helpful University FAQ assistant. "
            "Answer using ONLY the retrieved handbook context below. "
            "If the answer is not in the context, say you don't know.\n\n"
            f"Retrieved context:\n{context}"
        )},
        *buffer_memory[-BUFFER_WINDOW:],
    ])
    buffer_memory.append({"role": "assistant", "content": response})
    return response

# %%
# 1b. SUMMARY MEMORY

summary = ""
recent_turns = []
RECENT_WINDOW = 2

def summarise(turns: list[dict]) -> str:
    text = "\n".join(f"{m['role']}: {m['content']}" for m in turns)
    return complete([
        {"role": "system", "content": "Summarise the key facts from this conversation in 1-2 sentences."},
        {"role": "user", "content": text},
    ])

def summary_chat(user_input: str) -> str:
    global summary, recent_turns
    context = rag_retrieve(user_input)
    recent_turns.append({"role": "user", "content": user_input})
    context_block = (f"Conversation summary so far:\n{summary}\n\n" if summary else "")
    response = complete([
        {"role": "system", "content": (
            "You are a helpful University FAQ assistant. Answer briefly. "
            "Answer using ONLY the retrieved handbook context below. "
            "If the answer is not in the context, say you don't know.\n\n"
            f"Retrieved context:\n{context}"
        )},
        {"role": "user", "content": context_block + user_input},
    ])
    recent_turns.append({"role": "assistant", "content": response})
    if len(recent_turns) >= RECENT_WINDOW * 2:
        summary = summarise(recent_turns)
        recent_turns = []
    return response

