# 2a. Guard 1 (Keyword)
INTEGRITY_KW = ['generate an essay', 'solve this', 'do my homework', 'answer this exam', 'answer to exam', 'make an essay', 'write my essay', 'cheat']

def is_integrity_violation(text: str) -> tuple[bool, str]:
    """Returns (blocked: bool, matched_keyword: str). Matched keyword is '' if not blocked."""
    lower = text.lower()
    for kw in INTEGRITY_KW:
        if kw in lower:
            return True, kw
    return False, ''

