# 2b. Guard 2 (Topic Filter)
HANDBOOK_TOPICS = {
    "ACADEMIC_POLICIES": "Question about the grading system, academic probation policy, attendance, and academic integrity policy",
    "CODE_OF_CONDUCT":   "Questions regarding the student code of conduct, disciplinary action, vandalism, harassment, bullying.",
    "OPERATIONS_DRESS_CODE_HEALTH": "Questions regarding the dress code, student uniforms, in-campus healthcare options, and emergency protocols",
    "OFF_TOPIC":         "Questions unrelated to the student handbook, e.g. food, politics, games, mental health",
}

TOPIC_SYSTEM_PROMPT = (
    "You are a topic classifier for the Oakridge Academy FAQ chatbot.\n\n"
    "Classify the user's message into EXACTLY ONE topic:\n"
    + "\n".join(f"- {k}: {v}" for k, v in HANDBOOK_TOPICS.items())
    + "\n\nRespond with ONLY a JSON object in this exact format:\n"
    '{"topic": "TOPIC_NAME", "allowed": true, "confidence": 0.95}\n\n'
    "Rules:\n"
    "- allowed is true for ACADEMIC_POLICIES, CODE_OF_CONDUCT, OPERATIONS_DRESS_CODE_HEALTH; false for OFF_TOPIC\n"
    "- confidence is a float between 0 and 1"
)

TOPIC_FEW_SHOT = [
    {"role": "user",      "content": "What is the minimum passing grade?"},
    {"role": "assistant", "content": '{"topic": "ACADEMIC_POLICIES", "allowed": true, "confidence": 0.98}'},
    {"role": "user",      "content": "Can I use my mobile phone in class?"},
    {"role": "assistant", "content": '{"topic": "CODE_OF_CONDUCT", "allowed": true, "confidence": 0.97}'},
    {"role": "user",      "content": "Can I wear my Oakridge polo on Monday?"},
    {"role": "assistant", "content": '{"topic": "OPERATIONS_DRESS_CODE_HEALTH", "allowed": true, "confidence": 0.96}'},
    {"role": "user",      "content": "Are there fast-food restaurants near the university?"},
    {"role": "assistant", "content": '{"topic": "OFF_TOPIC", "allowed": false, "confidence": 0.92}'},
]

def is_on_topic(user_message: str, model: str = MODEL) -> dict:
    messages = [
        {"role": "system", "content": TOPIC_SYSTEM_PROMPT},
        *TOPIC_FEW_SHOT,
        {"role": "user",   "content": user_message},
    ]
    response = complete(messages, model)
    try:
        match = re.search(r'\{.*?\}', response, re.DOTALL)
        if not match:
            raise ValueError("No JSON found")
        result = json.loads(match.group())
        if result.get("topic") not in HANDBOOK_TOPICS:
            return {"topic": "UNKNOWN", "allowed": True, "confidence": 0.0, "fallback": True}
        return result
    except (json.JSONDecodeError, ValueError):
        return {"topic": "UNKNOWN", "allowed": True, "confidence": 0.0, "fallback": True}

