# 2c. Guard 3 (PII Redactor)
def redact_pii(text: str) -> str:
    """Replace personal identifiers with [REDACTED]."""

    # Phone numbers: Philippine formats
    text = re.sub(
        r'\b(?:\+63[-\s]?|0)9\d{2}[-\.\s]?\d{3,4}[-\.\s]?\d{4}\b',
        '[REDACTED]', text
    )

    # Email addresses
    text = re.sub(
        r'\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}\b',
        '[REDACTED]', text
    )

    # Ages
    text = re.sub(
        r'\b\d{1,3}[ \-]years?[ \-]old\b',
        '[REDACTED]', text, flags=re.IGNORECASE
    )

    # Street addresses
    text = re.sub(
        r'\b\d+\s+[A-Za-z][A-Za-z ]+?(?:St(?:reet)?|Ave(?:nue)?|Blvd|Road|Rd|Drive|Dr|Lane|Ln)\.?\b',
        '[REDACTED]', text, flags=re.IGNORECASE
    )

    # Full names after identity triggers
    text = re.sub(
        r'(My name is|my name is|I am)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)+)',
        r'\1 [REDACTED]', text
    )

    # Philippine National ID: XXXX-XXXXXXX-X
    text = re.sub(
        r'\b\d{4}-\d{7}-\d{1}\b',
        '[REDACTED]', text
    )

    return text

