# 2d. Output Validator

ESSAY_KW = ['here is your essay', 'in conclusion', 'attached below is']

def output_validator(response: str) -> str:
    response = redact_pii(response)
    lower = response.lower()
    for kw in ESSAY_KW:
        if kw in lower:
            return "I am not authorized to assist with your request. Please refer to the student handbook regarding the academic integrity policy."
    return response

