# TEMPLATE FROM HEALTHCAREBOT, SWAPPED IN FOR FAQBOT

class FAQBot:
    def __init__(self, student_id: str):
        self.memory = PatientMemory(student_id)

    def _input_guard(self, text: str) -> str:
        # Guard 1: keyword block
        blocked, kw = is_integrity_violation(text)
        if blocked:
            raise ValueError(f"Academic integrity violation blocked: '{kw}' detected")

        # Guard 3: PII redactor
        clean = redact_pii(text)

        # Guard 2: topic filter
        topic_result = is_on_topic(clean)
        if not topic_result.get("allowed", True):
            raise ValueError(f"Off-topic request blocked: topic='{topic_result.get('topic')}'")

        return clean

        return clean

    def _output_guard(self, response: str) -> str:
        return output_validator(response)

    def chat(self, user_input: str) -> str:
        clean      = self._input_guard(user_input)
        memory_ctx = self.memory.recall(clean)
        rag_ctx    = rag_retrieve(clean)
        context    = f"Student history:\n{memory_ctx}\n\nHandbook context:\n{rag_ctx}" if memory_ctx else f"Handbook context:\n{rag_ctx}"
        raw        = complete([
            {"role": "system", "content": (
                "You are a University Student Handbook FAQ assistant. "
                "Answer using ONLY the provided handbook context. "
                "If the answer is not in the context, say you don't know. "
                "Do NOT write essays, assignments, or academic work for students."
            )},
            {"role": "user", "content": f"Context:\n{context}\n\nQuestion: {clean}"},
        ])
        safe       = self._output_guard(raw)
        self.memory.remember(clean + " → " + safe)
        return safe

